#include <stdio.h>
#include <sys/time.h>
#include <float.h>
#include <omp.h>
#include <stdlib.h>
#include <string.h>

#define min( a, b )         a > b ? b : a
#define ceilDiv( a, b )     ( a + b - 1 ) / b
#define print( x )          printf( #x ": %lu\n", (unsigned long) x )
#define DEBUG               false

#define DEFAULT_THREADS_PER_BLOCK 256

#define MAX_ARGS 10
#define REC_LENGTH 53 // size of a record in db
#define LATITUDE_POS 28  // character position of the latitude value in each record
#define OPEN 10000  // initial value of nearest neighbors
#define MAX_RECORDS 1000000 // maximum number of records

typedef struct latLong
{
  float lat;
  float lng;
} LatLong;

typedef struct record
{
  char recString[REC_LENGTH];
  float distance;
} Record;

int loadData(char *filename,Record *records,LatLong *locations);
void findLowest(Record *records,float *distances,int numRecords,int topN);
void printUsage();
int parseCommandline(int argc, char *argv[], char* filename,int *r,float *lat,float *lng,
                     int *q, int *t, int *p, int *d);

int main(int argc, char* argv[])
{
  int    i=0;
  float lat, lng;
  int quiet=0,timing=0,platform=0,device=0;

  Record records[MAX_RECORDS];
  LatLong locations[MAX_RECORDS];
  char filename[100];
  int resultsCount=10;

  if (parseCommandline(argc, argv, filename,&resultsCount,&lat,&lng,
                       &quiet, &timing, &platform, &device)) {
    printUsage();
    return 0;
  }

  int numRecords = loadData(filename,records,locations);
  if (resultsCount > numRecords) resultsCount = numRecords;

  float *distances = (float *)malloc(sizeof(float) * numRecords);

  #pragma omp parallel for
  for (int globalId = 0; globalId < numRecords; globalId++) {
    LatLong *latLong = &locations[globalId];
    float *dist = &distances[globalId];
    *dist = (float)sqrt((lat-latLong->lat)*(lat-latLong->lat)+(lng-latLong->lng)*(lng-latLong->lng));
  }

  findLowest(records,distances,numRecords,resultsCount);

  if (!quiet)
    for(i=0;i<resultsCount;i++) {
      printf("%s --> Distance=%f\n",records[i].recString,records[i].distance);
    }
  free(distances);
  return 0;
}

int loadData(char *filename,Record *records,LatLong *locations){
  FILE   *flist,*fp;
  int    i=0;
  char dbname[64];
  int recNum=0;

  flist = fopen(filename, "r");
  while(!feof(flist)) {
    if(fscanf(flist, "%s\n", dbname) != 1) {
      fprintf(stderr, "error reading filelist\n");
      exit(0);
    }
    fp = fopen(dbname, "r");
    if(!fp) {
      printf("error opening a db\n");
      exit(1);
    }
    while(!feof(fp)){
      Record record;
      LatLong latLong;
      fgets(record.recString,49,fp);
      fgetc(fp); // newline
      if (feof(fp)) break;

      char substr[6];

      for(i=0;i<5;i++) substr[i] = *(record.recString+i+28);
      substr[5] = '\0';
      latLong.lat = atof(substr);

      for(i=0;i<5;i++) substr[i] = *(record.recString+i+33);
      substr[5] = '\0';
      latLong.lng = atof(substr);

      locations[recNum] = latLong;
      records[recNum] = record;
      recNum++;
      if (recNum >= MAX_RECORDS) {
        fprintf(stderr, "Too many records. Increase MAX_RECORDS.\n");
        exit(1);
      }
    }
    fclose(fp);
  }
  fclose(flist);
  return recNum;
}

void findLowest(Record *records,float *distances,int numRecords,int topN){
  int i,j;
  float val;
  int minLoc;
  Record tempRec;
  float tempDist;

  for(i=0;i<topN;i++) {
    minLoc = i;
    for(j=i;j<numRecords;j++) {
      val = distances[j];
      if (val < distances[minLoc]) minLoc = j;
    }
    tempRec = records[i];
    records[i] = records[minLoc];
    records[minLoc] = tempRec;

    tempDist = distances[i];
    distances[i] = distances[minLoc];
    distances[minLoc] = tempDist;

    records[i].distance = distances[i];
  }
}

int parseCommandline(int argc, char *argv[], char* filename,int *r,float *lat,float *lng,
                     int *q, int *t, int *p, int *d){
  int i;
  if (argc < 2) return 1; 
  strncpy(filename,argv[1],100);
  char flag;

  for(i=1;i<argc;i++) {
    if (argv[i][0]=='-') {// flag
      flag = argv[i][1];
      switch (flag) {
        case 'r': 
          i++;
          *r = atoi(argv[i]);
          break;
        case 'l': 
          if (argv[i][2]=='a') {//lat
            *lat = atof(argv[i+1]);
          }
          else {//lng
            *lng = atof(argv[i+1]);
          }
          i++;
          break;
        case 'h': 
          return 1;
        case 'q': 
          *q = 1;
          break;
        case 't': 
          *t = 1;
          break;
        case 'p': 
          i++;
          *p = atoi(argv[i]);
          break;
        case 'd': 
          i++;
          *d = atoi(argv[i]);
          break;
      }
    }
  }
  if ((*d >= 0 && *p<0) || (*p>=0 && *d<0)) 
    return 1;
  return 0;
}

